 * Table de codes errno (numero, nom, description)
 * Meme pattern : tableau de struct + boucle printf
 * avec formatage en colonnes alignees.
 * ================================================= */
typedef struct { int code; const char *name; const char *desc; } ErrInfo;

void example_errno_table(void) {
    ErrInfo errs[] = {
        {1,  "EPERM",  "Operation not permitted"},
        {2,  "ENOENT", "No such file or directory"},
        {13, "EACCES", "Permission denied"},
        {22, "EINVAL", "Invalid argument"},
    };
    printf("%-4s %-10s %s\n", "NUM", "NAME", "DESCRIPTION");
    for (int i = 0; i < 4; i++)
        printf("%-4d %-10s %s\n", errs[i].code, errs[i].name, errs[i].desc);
